#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
const int N=55,M=4005;
int ql[M],qr[M],qw[M],n,m,g[N][N][M],f[N][N][M],s[N][N][M],P[M],p;
struct Plan{int i,k;}q[N][N][M];int a[N],RT;
inline void dfs(int l,int r,Plan c)
{
	
	a[c.k]=P[c.i];if(l>=r)return;
	if(l<=c.k-1)rep(c.i,p,j)if(f[l][c.k-1][j]==s[l][c.k-1][c.i]){RT=c.i;dfs(l,c.k-1,q[l][c.k-1][j]);break;}
	if(c.k+1<=r)rep(c.i,p,j)if(f[c.k+1][r][j]==s[c.k+1][r][c.i]){RT=c.i;dfs(c.k+1,r,q[c.k+1][r][j]);break;}
}
int main()
{
	n=read();m=read();
	rep(1,m,i)ql[i]=read(),qr[i]=read(),P[i]=qw[i]=read();
	std::sort(P+1,P+m+1);p=std::unique(P+1,P+m+1)-P-1;
	rep(1,m,i)++g[ql[i]][qr[i]][qw[i]=std::lower_bound(P+1,P+p+1,qw[i])-P];
	
	for(int T=2;T<=n;++T)
	{
		for(int l=1,r=T;r<=n;++l,++r)
		{
			rep(1,p,i)g[l][r][i]+=g[l+1][r][i]+g[l][r-1][i]-g[l+1][r-1][i];
		}
	}
	for(int T=1;T<=n;++T)
	{
		for(int l=1,r=T;r<=n;++l,++r)
		{
			drep(p-1,1,i)g[l][r][i]+=g[l][r][i+1];
			rep(1,p,i)g[l][r][i]*=P[i];
		}
	}
	
	for(int T=1;T<=n;++T)
	{
		for(int l=1,r=T;r<=n;++l,++r)
		{
			rep(1,p,i)rep(l,r,k)
			{
				int tmp=s[l][k-1][i]+(g[l][r][i]-g[l][k-1][i]-g[k+1][r][i])+s[k+1][r][i];
				if(tmp>=f[l][r][i])q[l][r][i]={i,k},f[l][r][i]=tmp;
			}
			drep(p,1,i)s[l][r][i]=max(s[l][r][i+1],f[l][r][i]);
		}
	}
	printf("%d\n",s[1][n][1]);Plan c={0,0};
	rep(1,p,i)if(f[1][n][i]==s[1][n][1]){c=q[1][n][i];break;}
	dfs(1,n,c);rep(1,n,i)printf("%d ",a[i]);puts("");
}
